#[extendr]
pub fn convert(html: String, options: Robj) -> Result<Robj> {
    use std::sync::Arc;
    use std::sync::Mutex;
    let visitor_robj: Option<Robj> = options
        .clone()
        .as_list()
        .and_then(|list| list.iter().find(|(k, _)| *k == "visitor").map(|(_, v)| v))
        .filter(|v| !v.is_null() && !v.is_na());
    let visitor_handle: Option<html_to_markdown_rs::visitor::VisitorHandle> = visitor_robj
        .map(|v| Arc::new(Mutex::new(RHtmlVisitorBridge::new(v))) as html_to_markdown_rs::visitor::VisitorHandle);
    let opts_local = crate::options::decode_options(options).map_err(|e| extendr_api::Error::Other(e))?;
    let mut opts: html_to_markdown_rs::ConversionOptions = opts_local.into();
    opts.visitor = visitor_handle;
    html_to_markdown_rs::convert(&html, Some(opts))
        .map(crate::types::conversion_result_to_robj)
        .map_err(|e| extendr_api::Error::Other(e.to_string()))
}

/// Newtype wrapper around `extendr_api::Robj` that asserts `Send + Sync`.
///
/// # Safety
///
/// R is single-threaded; user-supplied R callbacks must only be invoked from the R main
/// thread. This wrapper exists to satisfy the `Send`/`Sync` bounds required by the Rust
/// plugin trait system and by `tokio::spawn_blocking`. Misuse from a background thread
/// triggers R-runtime undefined behaviour.
#[repr(transparent)]
#[derive(Clone)]
pub(crate) struct SendRobj(pub extendr_api::Robj);
// SAFETY: see SendRobj docs.
unsafe impl Send for SendRobj {}
// SAFETY: see SendRobj docs.
unsafe impl Sync for SendRobj {}
impl SendRobj {
    /// Consume the wrapper and yield the inner `Robj`. Used inside `spawn_blocking`
    /// closures so that the closure captures the whole `SendRobj` (which is `Send`)
    /// rather than the inner `Robj` field (which is `!Send`) under 2021+ disjoint
    /// capture rules.
    #[inline]
    pub(crate) fn into_inner(self) -> extendr_api::Robj {
        self.0
    }
}

fn nodecontext_to_robj(ctx: &html_to_markdown_rs::visitor::NodeContext) -> extendr_api::Robj {
    use extendr_api::prelude::*;
    let attrs_pairs: Vec<(&str, extendr_api::Robj)> = ctx
        .attributes
        .iter()
        .map(|(k, v)| (k.as_str(), extendr_api::Robj::from(v.as_str())))
        .collect();
    let attrs: extendr_api::Robj = List::from_pairs(attrs_pairs).into();
    list!(
        node_type = format!("{:?}", ctx.node_type),
        tag_name = ctx.tag_name.as_str(),
        depth = ctx.depth as i32,
        index_in_parent = ctx.index_in_parent as i32,
        is_inline = ctx.is_inline,
        parent_tag = ctx.parent_tag.as_deref().unwrap_or(""),
        attributes = attrs,
    )
    .into()
}

